import { Tab, InterviewRecord } from '../types';
import { Home as HomeIcon, User as UserIcon, Plus } from 'lucide-react';
import Home from './Home';
import NewInterview from './NewInterview';
import Profile from './Profile';
import InterviewDetail from './InterviewDetail';
import Notifications, { Notification } from './Notifications';

interface MainContainerProps {
  phone: string;
  onLogout: () => void;
}

const MainContainer: React.FC<MainContainerProps> = ({ phone, onLogout }) => {
  const [activeTab, setActiveTab] = useState<Tab>(Tab.HOME);
  const [profileIntent, setProfileIntent] = useState<'templates' | 'questionnaire' | null>(null);
  const [showNotifications, setShowNotifications] = useState(false);

  const [selectedInterview, setSelectedInterview] = useState<InterviewRecord | null>(null);

  const [records, setRecords] = useState<(InterviewRecord & { archived: boolean })[]>([
    { id: '1', clientName: '李总', company: '百度(中国)', status: 'SIGNED', time: '1小时前', summary: '对二期方案非常满意，已完成电子签。后续需跟进部署及技术培训事宜。', archived: false },
    { id: '2', clientName: '王经理', company: '美团外卖', status: 'FOLLOWING', time: '4小时前', summary: '价格敏感度较高，正在内部申请折扣权限，预计周五前给予初步反馈。', archived: false },
    { id: '3', clientName: '张经理', company: '腾讯科技', status: 'FOLLOWING', time: '2天前', summary: '初步接触，客户对数字化转型有浓厚兴趣，需准备详细案例。', archived: false },
    { id: '4', clientName: '陈总', company: '阿里巴巴', status: 'FOLLOWING', time: '3天前', summary: '探讨了云服务迁移方案。', archived: false },
    { id: '5', clientName: '赵主管', company: '字节跳动', status: 'SIGNED', time: '4天前', summary: '短视频营销合作达成意向。', archived: false },
    { id: '6', clientName: '孙总', company: '华为技术', status: 'PENDING', time: '5天前', summary: '5G基站建设方案初稿确认。', archived: false },
    { id: '7', clientName: '周经理', company: '小米集团', status: 'FOLLOWING', time: '1周前', summary: 'IoT设备集采价格谈拢。', archived: false },
    { id: '8', clientName: '吴总', company: '拼多多', status: 'SIGNED', time: '1周前', summary: '供应链金融项目正式上线。', archived: false },
    { id: '9', clientName: '郑老板', company: '京东物流', status: 'FOLLOWING', time: '2周前', summary: '智能仓储扩建需求跟进。', archived: false },
    { id: '10', clientName: '王总', company: '网易游戏', status: 'SIGNED', time: '2周前', summary: '海外发行合作框架协议签署。', archived: false },
    { id: '11', clientName: '赵总', company: '小米集团', status: 'SIGNED', time: '3天前', summary: '三期合同已落位，目前正在进行资源对齐，进展顺利。', archived: true },
    { id: '12', clientName: '周主管', company: '京东集团', status: 'SIGNED', time: '1周前', summary: '年度复盘会圆满结束，客户评价极高。', archived: true },
    { id: '13', clientName: '马老板', company: '网易公司', status: 'FOLLOWING', time: '2周前', summary: '正在探讨新的游戏发行渠道，对方有强烈合作意愿。', archived: true },
    { id: '14', clientName: '刘经理', company: '联想集团', status: 'SIGNED', time: '3周前', summary: 'PC设备更新项目交付完成。', archived: true },
    { id: '15', clientName: '钱主管', company: '携程旅行', status: 'SIGNED', time: '1个月前', summary: '企业差旅管理系统上线。', archived: true },
  ]);

  const navigateToTab = (tab: Tab, intent?: 'templates' | 'questionnaire') => {
    setActiveTab(tab);
    setSelectedInterview(null);
    if (intent) {
      setProfileIntent(intent);
    } else {
      setProfileIntent(null);
    }
  };

  const handleArchive = (id: string) => {
    setRecords(prev => prev.map(r => r.id === id ? { ...r, archived: true } : r));
    setSelectedInterview(null);
  };

  const handleNotificationClick = (notif: Notification) => {
    setShowNotifications(false); // 关闭通知中心

    // 如果通知关联了具体的访谈ID
    if (notif.relatedId) {
      const record = records.find(r => r.id === notif.relatedId);
      if (record) {
        setSelectedInterview(record);
        return;
      }
    }

    // 如果是提醒更新模版
    if (notif.type === 'alert' && notif.content.includes('模版')) {
      navigateToTab(Tab.PROFILE, 'templates');
      return;
    }

    // 默认行为
    navigateToTab(Tab.HOME);
  };

  const renderContent = () => {
    if (selectedInterview) {
      return (
        <InterviewDetail 
          record={selectedInterview} 
          onBack={() => setSelectedInterview(null)} 
          onArchive={() => handleArchive(selectedInterview.id)} 
        />
      );
    }

    switch (activeTab) {
      case Tab.HOME: 
        return (
          <Home 
            phone={phone} 
            onNavigate={navigateToTab} 
            records={records}
            onSelectRecord={(record) => setSelectedInterview(record)}
            onOpenNotifications={() => setShowNotifications(true)}
          />
        );
      case Tab.NEW_INTERVIEW: 
        return <NewInterview />;
      case Tab.PROFILE: 
        return (
          <Profile 
            phone={phone} 
            onLogout={onLogout} 
            initialIntent={profileIntent} 
            onIntentHandled={() => setProfileIntent(null)}
          />
        );
      default: 
        return <Home phone={phone} onNavigate={navigateToTab} records={records} onSelectRecord={setSelectedInterview} onOpenNotifications={() => setShowNotifications(true)} />;
    }
  };

  return (
    <div className="h-full flex flex-col relative overflow-hidden bg-slate-50">
      <div className="flex-1 relative overflow-hidden">
        {renderContent()}
      </div>

      {/* 消息通知中心 Overlay */}
      {showNotifications && (
        <Notifications 
          onClose={() => setShowNotifications(false)} 
          onNotificationClick={handleNotificationClick}
        />
      )}

      {/* Navigation Bar */}
      {!selectedInterview && !showNotifications && (
        <div className="absolute bottom-0 left-0 right-0 bg-white/95 backdrop-blur-md border-t border-gray-100 px-8 py-4 flex justify-between items-end z-[100] h-24 animate-[slideUpNav_0.3s_ease-out]">
          <button 
            onClick={() => navigateToTab(Tab.HOME)}
            className={`flex flex-col items-center space-y-1 transition-all ${
              activeTab === Tab.HOME ? 'text-blue-600' : 'text-gray-300'
            }`}
          >
            <HomeIcon size={24} strokeWidth={2.5} />
            <span className="text-[10px] font-black uppercase tracking-widest">首页</span>
          </button>

          <div className="relative -top-6">
            <button 
              onClick={() => navigateToTab(Tab.NEW_INTERVIEW)}
              className={`w-16 h-16 rounded-full flex items-center justify-center transition-all duration-300 shadow-2xl ${
                activeTab === Tab.NEW_INTERVIEW 
                  ? 'bg-blue-600 scale-110 shadow-blue-300' 
                  : 'bg-slate-800 shadow-slate-200'
              }`}
            >
              <Plus size={32} className="text-white" strokeWidth={2.5} />
            </button>
          </div>

          <button 
            onClick={() => navigateToTab(Tab.PROFILE)}
            className={`flex flex-col items-center space-y-1 transition-all ${
              activeTab === Tab.PROFILE ? 'text-blue-600' : 'text-gray-300'
            }`}
          >
            <UserIcon size={24} strokeWidth={2.5} />
            <span className="text-[10px] font-black uppercase tracking-widest">我的</span>
          </button>
        </div>
      )}

      <style>{`
        @keyframes slideUpNav {
          from { transform: translateY(100%); }
          to { transform: translateY(0); }
        }
      `}</style>
    </div>
  );
};

export default MainContainer;

