          />
        );
      default: 
        return <Home phone={phone} onNavigate={navigateToTab} records={records} onSelectRecord={setSelectedInterview} onOpenNotifications={() => setShowNotifications(true)} />;
    }
  };

  return (
    <div className="h-full flex flex-col relative overflow-hidden bg-slate-50">
      <div className="flex-1 relative overflow-hidden">
        {renderContent()}
      </div>

      {/* 消息通知中心 Overlay */}
      {showNotifications && (
        <Notifications 
          onClose={() => setShowNotifications(false)} 
          onNotificationClick={handleNotificationClick}
        />
      )}

      {/* Navigation Bar */}
      {!selectedInterview && !showNotifications && (
        <div className="absolute bottom-0 left-0 right-0 bg-white/95 backdrop-blur-md border-t border-gray-100 px-8 py-4 flex justify-between items-end z-[100] h-24 animate-[slideUpNav_0.3s_ease-out]">
          <button 
            onClick={() => navigateToTab(Tab.HOME)}
            className={`flex flex-col items-center space-y-1 transition-all ${
              activeTab === Tab.HOME ? 'text-blue-600' : 'text-gray-300'
            }`}
          >
            <HomeIcon size={24} strokeWidth={2.5} />
            <span className="text-[10px] font-black uppercase tracking-widest">首页</span>
          </button>

          <div className="relative -top-6">
            <button 
              onClick={() => navigateToTab(Tab.NEW_INTERVIEW)}
              className={`w-16 h-16 rounded-full flex items-center justify-center transition-all duration-300 shadow-2xl ${
                activeTab === Tab.NEW_INTERVIEW 
                  ? 'bg-blue-600 scale-110 shadow-blue-300' 
                  : 'bg-slate-800 shadow-slate-200'
              }`}
            >
              <Plus size={32} className="text-white" strokeWidth={2.5} />
            </button>
          </div>

          <button 
            onClick={() => navigateToTab(Tab.PROFILE)}
            className={`flex flex-col items-center space-y-1 transition-all ${
              activeTab === Tab.PROFILE ? 'text-blue-600' : 'text-gray-300'
