      icon: <Zap size={24} />,
      color: "from-blue-600 to-indigo-700",
    },
    {
      title: "智能资料分析",
      desc: "自动识别客户意向，挖掘隐藏商机",
      tag: "SMART AI",
      icon: <FileSearch size={24} />,
      color: "from-indigo-700 to-purple-800",
    }
  ];

  useEffect(() => {
    const timer = setInterval(() => setCurrentBanner(prev => (prev + 1) % banners.length), 5000);
    return () => clearInterval(timer);
  }, [banners.length]);

  const filteredRecords = records.filter(r => activeCategory === 'archived' ? r.archived : !r.archived);

  return (
    <div className="h-full bg-slate-50 flex flex-col relative">
