        </div>

        {/* 精简轮播图 */}
        <div className="relative mb-8 h-40 rounded-[32px] overflow-hidden shadow-xl shadow-blue-900/10 group active:scale-[0.98] transition-all cursor-pointer">
          <div 
            className="flex h-full transition-transform duration-700 ease-[cubic-bezier(0.16,1,0.3,1)]"
            style={{ transform: `translateX(-${currentBanner * 100}%)` }}
