}

const MainContainer: React.FC<MainContainerProps> = ({ phone, onLogout }) => {
  const [activeTab, setActiveTab] = useState<Tab>(Tab.HOME);
  const [profileIntent, setProfileIntent] = useState<'templates' | 'questionnaire' | null>(null);
  const [showNotifications, setShowNotifications] = useState(false);

  const [selectedInterview, setSelectedInterview] = useState<InterviewRecord | null>(null);

  // 模拟数据：添加一些已生成报告的标记
  const [records, setRecords] = useState<(InterviewRecord & { archived: boolean })[]>([
    { id: '1', clientName: '李总', company: '百度(中国)', status: 'SIGNED', time: '1小时前', summary: '对二期方案非常满意，已完成电子签。后续需跟进部署及技术培训事宜。', archived: false, reportStatus: 'GENERATED' },
    { id: '2', clientName: '王经理', company: '美团外卖', status: 'FOLLOWING', time: '4小时前', summary: '价格敏感度较高，正在内部申请折扣权限，预计周五前给予初步反馈。', archived: false, reportStatus: 'NONE' },
    { id: '3', clientName: '张经理', company: '腾讯科技', status: 'FOLLOWING', time: '2天前', summary: '初步接触，客户对数字化转型有浓厚兴趣，需准备详细案例。', archived: false, reportStatus: 'GENERATED' },
    { id: '4', clientName: '陈总', company: '阿里巴巴', status: 'FOLLOWING', time: '3天前', summary: '探讨了云服务迁移方案。', archived: false, reportStatus: 'NONE' },
    { id: '5', clientName: '赵主管', company: '字节跳动', status: 'SIGNED', time: '4天前', summary: '短视频营销合作达成意向。', archived: false, reportStatus: 'GENERATED' },
    { id: '11', clientName: '赵总', company: '小米集团', status: 'SIGNED', time: '3天前', summary: '三期合同已落位，目前正在进行资源对齐，进展顺利。', archived: true, reportStatus: 'GENERATED' },
  ]);

  const navigateToTab = (tab: Tab, intent?: 'templates' | 'questionnaire') => {
    setActiveTab(tab);
    setSelectedInterview(null);
    if (intent) {
      setProfileIntent(intent);
    } else {
      setProfileIntent(null);
    }
  };

  const handleArchive = (id: string) => {
    setRecords(prev => prev.map(r => r.id === id ? { ...r, archived: true } : r));
    setSelectedInterview(null);
  };

  const handleNotificationClick = (notif: Notification) => {
    setShowNotifications(false);
    if (notif.relatedId) {
      const record = records.find(r => r.id === notif.relatedId);
      if (record) {
        setSelectedInterview(record);
        return;
      }
    }
    navigateToTab(Tab.HOME);
  };

  const renderContent = () => {
    if (selectedInterview) {
      return (
        <InterviewDetail 
          record={selectedInterview} 
          onBack={() => setSelectedInterview(null)} 
          onArchive={() => handleArchive(selectedInterview.id)} 
        />
      );
    }

    switch (activeTab) {
      case Tab.HOME: 
        return (
          <Home 
            phone={phone} 
            onNavigate={navigateToTab} 
            records={records}
            onSelectRecord={(record) => setSelectedInterview(record)}
            onOpenNotifications={() => setShowNotifications(true)}
          />
        );
      case Tab.REPORTS:
        return <Reports records={records} onSelectRecord={setSelectedInterview} />;
      case Tab.NEW_INTERVIEW: 
        return <NewInterview />;
      case Tab.MANAGEMENT:
        return (
          <Management 
            onOpenTemplates={() => setProfileIntent('templates')}
            onOpenQuestionnaire={() => setProfileIntent('questionnaire')}
          />
        );
      case Tab.PROFILE: 
        return <Profile phone={phone} onLogout={onLogout} />;
      default: 
        return <Home phone={phone} onNavigate={navigateToTab} records={records} onSelectRecord={setSelectedInterview} onOpenNotifications={() => setShowNotifications(true)} />;
    }
  };

  // 辅助渲染导航项
  const NavItem = ({ tab, icon: Icon, label }: { tab: Tab, icon: any, label: string }) => (
    <button 
      onClick={() => navigateToTab(tab)}
      className={`flex flex-col items-center space-y-1 transition-all flex-1 ${
        activeTab === tab ? 'text-blue-600' : 'text-slate-300'
      }`}
    >
      <Icon size={22} strokeWidth={activeTab === tab ? 2.5 : 2} />
      <span className="text-[9px] font-black uppercase tracking-wider">{label}</span>
    </button>
  );

  return (
    <div className="h-full flex flex-col relative overflow-hidden bg-slate-50">
      <div className="flex-1 relative overflow-hidden">
        {renderContent()}
      </div>

      {showNotifications && (
        <Notifications 
          onClose={() => setShowNotifications(false)} 
          onNotificationClick={handleNotificationClick}
        />
      )}

      {/* 底部导航栏：5 项布局 */}
      {!selectedInterview && !showNotifications && (
        <div className="bg-white/95 backdrop-blur-md border-t border-slate-100 px-2 py-4 flex justify-between items-center z-[100] h-24 animate-[slideUpNav_0.3s_ease-out]">
          <NavItem tab={Tab.HOME} icon={HomeIcon} label="首页" />
          <NavItem tab={Tab.REPORTS} icon={FileText} label="报告" />

          {/* 发起按钮 */}
          <div className="relative -top-6 flex-1 flex justify-center">
            <button 
              onClick={() => navigateToTab(Tab.NEW_INTERVIEW)}
              className={`w-14 h-14 rounded-full flex items-center justify-center transition-all duration-300 shadow-xl ${
                activeTab === Tab.NEW_INTERVIEW 
                  ? 'bg-blue-600 scale-110 shadow-blue-200' 
                  : 'bg-slate-800 shadow-slate-200'
              }`}
            >
              <Plus size={28} className="text-white" strokeWidth={3} />
            </button>
          </div>

          <NavItem tab={Tab.MANAGEMENT} icon={Layers} label="管理" />
          <NavItem tab={Tab.PROFILE} icon={UserIcon} label="我的" />
        </div>
      )}

      {/* 模版和问题清单覆盖层 (复用 Profile 的逻辑，这里通过 profileIntent 渲染) */}
      {profileIntent === 'templates' && (
        <div className="absolute inset-0 z-[550]">
          <Profile phone={phone} onLogout={onLogout} initialIntent="templates" onIntentHandled={() => setProfileIntent(null)} />
        </div>
      )}
      {profileIntent === 'questionnaire' && (
        <div className="absolute inset-0 z-[550]">
          <Profile phone={phone} onLogout={onLogout} initialIntent="questionnaire" onIntentHandled={() => setProfileIntent(null)} />
        </div>
      )}

      <style>{`
        @keyframes slideUpNav { from { transform: translateY(100%); } to { transform: translateY(0); } }
      `}</style>
    </div>
  );
};

export default MainContainer;

import React, { useState } from 'react';
import { Tab, InterviewRecord } from '../types';
import { Home as HomeIcon, User as UserIcon, Plus, FileText, Layers } from 'lucide-react';
import Home from './Home';
import NewInterview from './NewInterview';
import Profile from './Profile';
import Reports from './Reports';
import Management from './Management';
import InterviewDetail from './InterviewDetail';
import Notifications, { Notification } from './Notifications';

interface MainContainerProps {
  phone: string;
  onLogout: () => void;
}

const MainContainer: React.FC<MainContainerProps> = ({ phone, onLogout }) => {
  const [activeTab, setActiveTab] = useState<Tab>(Tab.HOME);
  const [profileIntent, setProfileIntent] = useState<'templates' | 'questionnaire' | null>(null);
  const [showNotifications, setShowNotifications] = useState(false);

  const [selectedInterview, setSelectedInterview] = useState<InterviewRecord | null>(null);

  const [records, setRecords] = useState<(InterviewRecord & { archived: boolean })[]>([
    { id: '1', clientName: '李总', company: '百度(中国)', status: 'SIGNED', time: '1小时前', summary: '对二期方案非常满意，已完成电子签。后续需跟进部署及技术培训事宜。', archived: false, reportStatus: 'GENERATED' },
    { id: '2', clientName: '王经理', company: '美团外卖', status: 'FOLLOWING', time: '4小时前', summary: '价格敏感度较高，正在内部申请折扣权限，预计周五前给予初步反馈。', archived: false, reportStatus: 'NONE' },
    { id: '3', clientName: '张经理', company: '腾讯科技', status: 'FOLLOWING', time: '2天前', summary: '初步接触，客户对数字化转型有浓厚兴趣，需准备详细案例。', archived: false, reportStatus: 'GENERATED' },
    { id: '4', clientName: '陈总', company: '阿里巴巴', status: 'FOLLOWING', time: '3天前', summary: '探讨了云服务迁移方案任务。', archived: false, reportStatus: 'NONE' },
    { id: '5', clientName: '赵主管', company: '字节跳动', status: 'SIGNED', time: '4天前', summary: '短视频营销合作达成意向。', archived: false, reportStatus: 'GENERATED' },
    { id: '11', clientName: '赵总', company: '小米集团', status: 'SIGNED', time: '3天前', summary: '三期合同已落位，目前正在进行资源对齐，进展顺利。', archived: true, reportStatus: 'GENERATED' },
  ]);

  const navigateToTab = (tab: Tab, intent?: 'templates' | 'questionnaire') => {
    setActiveTab(tab);
    setSelectedInterview(null);
    setProfileIntent(intent || null);
  };

  const handleArchive = (id: string) => {
    setRecords(prev => prev.map(r => r.id === id ? { ...r, archived: true } : r));
    setSelectedInterview(null);
  };

  const handleNotificationClick = (notif: Notification) => {
    setShowNotifications(false);
    if (notif.relatedId) {
      const record = records.find(r => r.id === notif.relatedId);
      if (record) {
        setSelectedInterview(record);
        return;
      }
    }
    navigateToTab(Tab.HOME);
  };

  const renderContent = () => {
    if (selectedInterview) {
      return (
        <InterviewDetail 
          record={selectedInterview} 
          onBack={() => setSelectedInterview(null)} 
          onArchive={() => handleArchive(selectedInterview.id)} 
        />
      );
    }

    switch (activeTab) {
      case Tab.HOME: 
        return (
          <Home 
            phone={phone} 
            onNavigate={navigateToTab} 
            records={records}
            onSelectRecord={(record) => setSelectedInterview(record)}
            onOpenNotifications={() => setShowNotifications(true)}
          />
        );
      case Tab.REPORTS:
        return <Reports records={records} onSelectRecord={setSelectedInterview} />;
      case Tab.NEW_INTERVIEW: 
        return <NewInterview />;
      case Tab.MANAGEMENT:
        return <Management />;
      case Tab.PROFILE: 
        return <Profile phone={phone} onLogout={onLogout} />;
      default: 
        return <Home phone={phone} onNavigate={navigateToTab} records={records} onSelectRecord={setSelectedInterview} onOpenNotifications={() => setShowNotifications(true)} />;
    }
  };

  const NavItem = ({ tab, icon: Icon, label }: { tab: Tab, icon: any, label: string }) => (
    <button 
      onClick={() => navigateToTab(tab)}
      className={`flex flex-col items-center space-y-1 transition-all flex-1 ${
        activeTab === tab ? 'text-blue-600' : 'text-slate-300'
      }`}
    >
      <Icon size={22} strokeWidth={activeTab === tab ? 2.5 : 2} />
      <span className="text-[9px] font-black uppercase tracking-wider">{label}</span>
    </button>
  );

  return (
    <div className="h-full flex flex-col relative overflow-hidden bg-slate-50">
      <div className="flex-1 relative overflow-hidden">
        {renderContent()}
      </div>

      {showNotifications && (
        <Notifications 
          onClose={() => setShowNotifications(false)} 
          onNotificationClick={handleNotificationClick}
        />
      )}

      {!selectedInterview && !showNotifications && (
        <div className="bg-white/95 backdrop-blur-md border-t border-slate-100 px-2 py-4 flex justify-between items-center z-[100] h-24 animate-[slideUpNav_0.3s_ease-out]">
          <NavItem tab={Tab.HOME} icon={HomeIcon} label="首页" />
          <NavItem tab={Tab.REPORTS} icon={FileText} label="报告" />

          <div className="relative -top-6 flex-1 flex justify-center">
            <button 
              onClick={() => navigateToTab(Tab.NEW_INTERVIEW)}
              className={`w-14 h-14 rounded-full flex items-center justify-center transition-all duration-300 shadow-xl ${
                activeTab === Tab.NEW_INTERVIEW 
                  ? 'bg-blue-600 scale-110 shadow-blue-200' 
                  : 'bg-slate-800 shadow-slate-200'
              }`}
            >
              <Plus size={28} className="text-white" strokeWidth={3} />
            </button>
          </div>

          <NavItem tab={Tab.MANAGEMENT} icon={Layers} label="管理" />
          <NavItem tab={Tab.PROFILE} icon={UserIcon} label="我的" />
        </div>
      )}

      <style>{`
        @keyframes slideUpNav { from { transform: translateY(100%); } to { transform: translateY(0); } }
      `}</style>
    </div>
  );
};

export default MainContainer;

import React, { useState } from 'react';
import { 
  Layers, 
  Upload, 
  ChevronRight, 
  ChevronLeft, 
  Search, 
  FileText, 
  CheckSquare, 
  Link as LinkIcon,
  Plus,
  Zap,
  ShieldCheck,
  Target,
  X,
  PlusCircle,
  FilePlus
} from 'lucide-react';

type SubView = 'main' | 'templates' | 'questions';

interface QuestionSet {
  id: string;
  title: string;
  desc: string;
  count: number;
  linkedTemplate?: string;
}

const Management: React.FC = () => {
  const [view, setView] = useState<SubView>('main');
  const [editingQuestionSet, setEditingQuestionSet] = useState<QuestionSet | null>(null);
  const [isCreatingNew, setIsCreatingNew] = useState(false);
  const [showBindingSelector, setShowBindingSelector] = useState(false);

  // 行业模版数据
  const templateCategories = [
    { id: 't1', name: '互联网/SaaS', icon: <Zap size={18} />, count: 12, templates: ['B端通用调研模版', '核心系统迁移评估', '数字化转型深度访谈'] },
    { id: 't2', name: '传统制造业', icon: <Layers size={18} />, count: 8, templates: ['供应链优化访谈', '数字化工厂建设', '能耗管理审计'] },
    { id: 't3', name: '金融/保险', icon: <ShieldCheck size={18} />, count: 5, templates: ['高净值客户资产配置', '普惠金融信贷评审'] }
  ];

  // 问题清单数据
  const [questionSets, setQuestionSets] = useState<QuestionSet[]>([
    { id: 'q1', title: '核心痛点挖掘', desc: '用于初次拜访，深挖业务瓶颈', count: 15, linkedTemplate: '互联网/SaaS' },
    { id: 'q2', title: '商务异议处理', desc: '针对价格、竞争对手的防御话术', count: 8, linkedTemplate: '通用模版' },
    { id: 'q3', title: '决策链调研', desc: '摸清内部审批流程与关键决策人', count: 6 },
  ]);

  // 新建状态管理
  const [newSetData, setNewSetData] = useState<Partial<QuestionSet>>({
    title: '',
    desc: '',
    linkedTemplate: undefined
  });

  const handleBindTemplate = (templateName: string) => {
    if (isCreatingNew) {
      setNewSetData(prev => ({ ...prev, linkedTemplate: templateName }));
    } else if (editingQuestionSet) {
      setQuestionSets(prev => prev.map(qs => 
        qs.id === editingQuestionSet.id ? { ...qs, linkedTemplate: templateName } : qs
      ));
    }
    setShowBindingSelector(false);
  };

  const handleCreateNew = () => {
    if (!newSetData.title) return;
    const newId = `q${Date.now()}`;
    const newEntry: QuestionSet = {
      id: newId,
      title: newSetData.title || '未命名清单',
      desc: newSetData.desc || '暂无描述',
      count: 0,
      linkedTemplate: newSetData.linkedTemplate
    };
    setQuestionSets([newEntry, ...questionSets]);
    setIsCreatingNew(false);
    setNewSetData({ title: '', desc: '', linkedTemplate: undefined });
  };

  const renderTemplatesView = () => (
    <div className="flex-1 flex flex-col bg-slate-50 animate-fade-in h-full">
      <div className="px-6 pt-12 pb-4 bg-white border-b border-slate-100 flex items-center justify-between">
        <div className="flex items-center space-x-4">
          <button onClick={() => setView('main')} className="p-1 -ml-1 text-slate-400 active:scale-90"><ChevronLeft size={28} /></button>
          <h3 className="text-xl font-black text-slate-900">模版中心</h3>
        </div>
        <button className="w-10 h-10 bg-blue-50 text-blue-600 rounded-xl flex items-center justify-center active:scale-90">
          <FilePlus size={20} strokeWidth={3} />
        </button>
      </div>
      <div className="px-6 py-4">
        <div className="relative">
          <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300" size={16} />
          <input 
            type="text" 
            placeholder="搜索行业模版..." 
            className="w-full h-11 pl-11 pr-4 bg-white rounded-2xl border border-slate-100 text-sm focus:outline-none focus:ring-2 focus:ring-blue-100 transition-all"
          />
        </div>
      </div>
      <div className="flex-1 overflow-y-auto px-6 pb-32 space-y-6">
        {templateCategories.map((cat, i) => (
          <div key={i} className="space-y-3">
            <div className="flex items-center justify-between px-2">
              <div className="flex items-center space-x-2">
                <span className="text-blue-600">{cat.icon}</span>
                <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{cat.name}</span>
              </div>
            </div>
            <div className="space-y-3">
              {cat.templates.map((t, j) => (
                <div key={j} className="w-full bg-white p-4 rounded-2xl border border-white shadow-sm flex items-center justify-between active:bg-slate-50 transition-all">
                  <div className="flex items-center space-x-3">
                    <div className="w-8 h-8 bg-slate-50 rounded-lg flex items-center justify-center text-slate-300">
                      <FileText size={16} />
                    </div>
                    <span className="text-sm font-bold text-slate-700">{t}</span>
                  </div>
                  <ChevronRight size={16} className="text-slate-200" />
                </div>
              ))}
            </div>
          </div>
        ))}
      </div>
    </div>
  );

  const renderQuestionsView = () => (
    <div className="flex-1 flex flex-col bg-slate-50 animate-fade-in h-full relative">
      <div className="px-6 pt-12 pb-4 bg-white border-b border-slate-100 flex items-center justify-between">
        <div className="flex items-center space-x-4">
          <button onClick={() => setView('main')} className="p-1 -ml-1 text-slate-400 active:scale-90"><ChevronLeft size={28} /></button>
          <h3 className="text-xl font-black text-slate-900">问题清单</h3>
        </div>
        <button 
          onClick={() => setIsCreatingNew(true)}
          className="w-10 h-10 bg-emerald-50 text-emerald-600 rounded-xl flex items-center justify-center active:scale-90"
        >
          <PlusCircle size={22} strokeWidth={2.5} />
        </button>
      </div>

      <div className="flex-1 overflow-y-auto px-6 pt-6 pb-32 space-y-4">
        {questionSets.map((set) => (
          <div 
            key={set.id} 
            className="w-full bg-white p-5 rounded-[32px] border border-white shadow-sm flex flex-col active:scale-[0.98] transition-all"
            onClick={() => setEditingQuestionSet(set)}
          >
            <div className="flex items-start justify-between mb-2">
              <div className="flex items-center space-x-3">
                <div className="w-10 h-10 bg-emerald-50 text-emerald-600 rounded-xl flex items-center justify-center">
                  <CheckSquare size={20} />
                </div>
                <div>
                  <h4 className="font-black text-slate-800 text-[15px]">{set.title}</h4>
                  <p className="text-[10px] text-slate-400 font-bold uppercase tracking-wider">{set.count} QUESTIONS</p>
                </div>
              </div>
              <ChevronRight size={18} className="text-slate-200 mt-1" />
            </div>
            <p className="text-[11px] text-slate-500 font-medium line-clamp-1 mb-3 px-1">{set.desc}</p>
            <div className="flex items-center justify-between pt-3 border-t border-slate-50">
              <div className="flex items-center space-x-1.5">
                <LinkIcon size={12} className={set.linkedTemplate ? "text-blue-500" : "text-slate-200"} />
                <span className={`text-[10px] font-black uppercase tracking-tight ${set.linkedTemplate ? "text-blue-600" : "text-slate-300"}`}>
                  {set.linkedTemplate ? `已关联: ${set.linkedTemplate}` : "未关联模版"}
                </span>
              </div>
            </div>
          </div>
        ))}
      </div>

      {/* 新建/编辑清单 Overlay */}
      {(isCreatingNew || editingQuestionSet) && (
        <div className="absolute inset-0 z-[200] bg-black/60 backdrop-blur-md flex items-end justify-center">
          <div className="w-full max-w-md bg-white rounded-t-[48px] p-8 animate-slide-up shadow-2xl">
            <div className="flex items-center justify-between mb-8">
              <h3 className="text-2xl font-black text-slate-900">
                {isCreatingNew ? '新建问题清单' : '清单设置'}
              </h3>
              <button 
                onClick={() => { setIsCreatingNew(false); setEditingQuestionSet(null); }} 
                className="w-10 h-10 bg-slate-100 rounded-full flex items-center justify-center active:scale-90"
              >
                <X size={20} />
              </button>
            </div>

            <div className="space-y-6">
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-300 uppercase tracking-widest px-1">清单名称</label>
                <input 
                  type="text"
                  placeholder="如：核心痛点挖掘-V2"
                  value={isCreatingNew ? newSetData.title : editingQuestionSet?.title}
                  onChange={(e) => isCreatingNew 
                    ? setNewSetData({ ...newSetData, title: e.target.value })
                    : setEditingQuestionSet(prev => prev ? { ...prev, title: e.target.value } : null)
                  }
                  className="w-full h-14 bg-slate-50 rounded-2xl px-5 font-bold text-slate-700 outline-none focus:ring-2 focus:ring-blue-100 transition-all"
                />
              </div>

              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-300 uppercase tracking-widest px-1">关联业务模版</label>
                <button 
                  onClick={() => setShowBindingSelector(true)}
                  className="w-full h-16 bg-blue-50/50 border-2 border-dashed border-blue-200 rounded-2xl flex items-center justify-between px-6 group active:bg-blue-100 transition-all"
                >
                  <div className="flex items-center space-x-3">
                    <LinkIcon size={18} className="text-blue-600" />
                    <span className="font-black text-blue-700">
                      {(isCreatingNew ? newSetData.linkedTemplate : editingQuestionSet?.linkedTemplate) || "点击绑定行业模版"}
                    </span>
                  </div>
                  <ChevronRight size={18} className="text-blue-300" />
                </button>
              </div>

              <div className="space-y-2 pb-4">
                <label className="text-[10px] font-black text-slate-300 uppercase tracking-widest px-1">简要描述</label>
                <textarea 
                  placeholder="描述此清单的使用场景..."
                  rows={2}
                  value={isCreatingNew ? newSetData.desc : editingQuestionSet?.desc}
                  onChange={(e) => isCreatingNew 
                    ? setNewSetData({ ...newSetData, desc: e.target.value })
                    : setEditingQuestionSet(prev => prev ? { ...prev, desc: e.target.value } : null)
                  }
                  className="w-full bg-slate-50 rounded-2xl p-5 font-medium text-slate-600 outline-none focus:ring-2 focus:ring-blue-100 transition-all resize-none"
                />
              </div>

              <button 
                onClick={isCreatingNew ? handleCreateNew : () => {
                   if (editingQuestionSet) {
                     setQuestionSets(prev => prev.map(q => q.id === editingQuestionSet.id ? editingQuestionSet : q));
                     setEditingQuestionSet(null);
                   }
                }}
                className="w-full py-5 bg-slate-900 text-white rounded-[24px] font-black text-sm shadow-2xl active:scale-95 transition-all"
              >
                {isCreatingNew ? '立即创建清单' : '保存修改'}
              </button>
            </div>
          </div>
        </div>
      )}

      {/* 模版选择器 */}
      {showBindingSelector && (
        <div className="absolute inset-0 z-[300] bg-white flex flex-col animate-fade-in">
          <div className="px-6 pt-12 pb-6 flex items-center space-x-4 border-b border-slate-50">
            <button onClick={() => setShowBindingSelector(false)} className="p-1"><ChevronLeft size={28} /></button>
            <h3 className="text-lg font-black text-slate-900">绑定行业资产</h3>
          </div>
          <div className="flex-1 overflow-y-auto p-6 space-y-4">
            {templateCategories.map((cat) => (
              <div key={cat.id} className="space-y-2">
                <p className="text-[10px] font-black text-slate-300 uppercase tracking-widest px-2">{cat.name}</p>
                <div className="space-y-2">
                   {cat.templates.map((t, idx) => (
                     <button 
                       key={idx} 
                       onClick={() => handleBindTemplate(cat.name)}
                       className="w-full p-5 bg-slate-50 rounded-2xl border border-slate-100 flex items-center justify-between active:bg-blue-50 active:border-blue-200 group transition-all"
