        >
          <LogOut size={18} />
          <span>退出登录</span>
        </button>
      </div>

      {showEditProfile && <EditProfileOverlay />}
      {showCoCreation && <CoCreationOverlay />}

      <style>{`
        @keyframes slide-up { from { transform: translateY(100%); opacity: 0; } to { transform: translateY(0); opacity: 1; } }
        .animate-slide-up { animation: slide-up 0.4s cubic-bezier(0.16, 1, 0.3, 1) forwards; }
      `}</style>
    </div>
  );
};

export default Profile;

import React, { useState } from 'react';
import { 
  Layers, 
  ChevronRight, 
  ChevronLeft, 
  FileText, 
  CheckSquare, 
  Link as LinkIcon,
  X,
  PlusCircle,
  Grid,
  Trash2,
  Plus,
  ArrowRight,
  Settings2,
  AlertCircle,
  Link2Off
} from 'lucide-react';

type SubView = 'main' | 'template-categories' | 'template-list' | 'questions' | 'question-editor';

interface TemplateCategory {
  id: string;
  name: string;
  icon: React.ReactNode;
  color: string;
  count: number;
  templates: string[];
}

interface QuestionSet {
  id: string;
  title: string;
  desc: string;
  questions: string[];
  linkedTemplate?: string;
}

const Management: React.FC = () => {
  const [view, setView] = useState<SubView>('main');
  const [selectedCat, setSelectedCat] = useState<TemplateCategory | null>(null);
  const [editingQuestionSet, setEditingQuestionSet] = useState<QuestionSet | null>(null);
  const [activeEditorSet, setActiveEditorSet] = useState<QuestionSet | null>(null);
  const [isCreatingNew, setIsCreatingNew] = useState(false);
  const [showBindingSelector, setShowBindingSelector] = useState(false);
  const [newQuestionInput, setNewQuestionInput] = useState('');

  // 行业模版分类数据
  const templateCategories: TemplateCategory[] = [
    { id: 't1', name: '互联网/SaaS', icon: <Layers size={22} />, color: 'bg-blue-500', count: 12, templates: ['B端通用调研模版', '核心系统迁移评估', '数字化转型深度访谈'] },
    { id: 't2', name: '传统制造业', icon: <Layers size={22} />, color: 'bg-orange-500', count: 8, templates: ['供应链优化访谈', '数字化工厂建设', '能耗管理审计'] },
    { id: 't3', name: '金融/保险', icon: <Layers size={22} />, color: 'bg-emerald-500', count: 5, templates: ['高净值客户资产配置', '普惠金融信贷评审'] },
    { id: 't4', name: '医疗健康', icon: <Layers size={22} />, color: 'bg-rose-500', count: 6, templates: ['智慧医疗系统需求', '医药合规访谈'] }
  ];

  // 问题清单数据
  const [questionSets, setQuestionSets] = useState<QuestionSet[]>([
    { id: 'q1', title: '核心痛点挖掘', desc: '用于初次拜访，深挖业务瓶颈', questions: ['目前最影响效率的环节是？', '是否有替换现有系统的计划？', '预算决策链包含哪些人？'], linkedTemplate: '互联网/SaaS' },
    { id: 'q2', title: '商务异议处理', desc: '针对价格、竞争对手的防御话术', questions: ['如何看待友商的报价？', '对我们服务时效的要求？'], linkedTemplate: '传统制造业' },
    { id: 'q3', title: '决策链调研', desc: '摸清内部审批流程与关键决策人', questions: [] },
  ]);

  // 新建状态管理
  const [newSetData, setNewSetData] = useState<Partial<QuestionSet>>({
    title: '',
    desc: '',
    linkedTemplate: undefined,
    questions: []
  });

  const handleSelectCategory = (cat: TemplateCategory) => {
    setSelectedCat(cat);
    setView('template-list');
  };

  // 核心逻辑：检查某个分类是否已被其他清单绑定
  const getBindingInfo = (templateName: string) => {
    return questionSets.find(q => q.linkedTemplate === templateName);
  };

  const handleBindTemplate = (templateName: string) => {
    const occupant = getBindingInfo(templateName);

    // 如果该模版已被当前正在编辑的清单占用，不需要特殊操作
    const currentId = isCreatingNew ? 'new' : editingQuestionSet?.id;
    if (occupant && occupant.id === currentId) {
      setShowBindingSelector(false);
      return;
    }

    // 执行绑定
    if (isCreatingNew) {
      setNewSetData(prev => ({ ...prev, linkedTemplate: templateName }));
    } else if (editingQuestionSet) {
      const updated = { ...editingQuestionSet, linkedTemplate: templateName };
      setEditingQuestionSet(updated);
      if (activeEditorSet?.id === updated.id) {
        setActiveEditorSet(updated);
      }
    }

    // 联动逻辑：如果模版之前被别的清单绑定，则需要清除旧清单的绑定
    if (occupant) {
      setQuestionSets(prev => prev.map(q => q.id === occupant.id ? { ...q, linkedTemplate: undefined } : q));
    }

    setShowBindingSelector(false);
  };

  const handleUnbindTemplate = () => {
    if (editingQuestionSet) {
      const updated = { ...editingQuestionSet, linkedTemplate: undefined };
      setEditingQuestionSet(updated);
      if (activeEditorSet?.id === updated.id) {
        setActiveEditorSet(updated);
      }
    }
  };

  const handleCreateNew = () => {
    if (!newSetData.title) return;
    const newId = `q${Date.now()}`;
    const newEntry: QuestionSet = {
      id: newId,
      title: newSetData.title || '未命名清单',
      desc: newSetData.desc || '暂无描述',
      questions: [],
      linkedTemplate: newSetData.linkedTemplate
    };
    setQuestionSets([newEntry, ...questionSets]);
    setIsCreatingNew(false);
    setNewSetData({ title: '', desc: '', linkedTemplate: undefined, questions: [] });
    setActiveEditorSet(newEntry);
    setView('question-editor');
  };

  const handleSaveSettings = () => {
    if (editingQuestionSet) {
      setQuestionSets(prev => prev.map(q => q.id === editingQuestionSet.id ? editingQuestionSet : q));
      if (activeEditorSet?.id === editingQuestionSet.id) {
        setActiveEditorSet(editingQuestionSet);
      }
      setEditingQuestionSet(null);
    }
  };

  const handleAddQuestion = () => {
    if (!newQuestionInput.trim() || !activeEditorSet) return;
    const updatedSet = {
      ...activeEditorSet,
      questions: [...activeEditorSet.questions, newQuestionInput.trim()]
    };
    setActiveEditorSet(updatedSet);
    setQuestionSets(prev => prev.map(q => q.id === updatedSet.id ? updatedSet : q));
    setNewQuestionInput('');
  };

  const handleDeleteQuestion = (index: number) => {
    if (!activeEditorSet) return;
    const updatedQuestions = [...activeEditorSet.questions];
    updatedQuestions.splice(index, 1);
    const updatedSet = { ...activeEditorSet, questions: updatedQuestions };
    setActiveEditorSet(updatedSet);
    setQuestionSets(prev => prev.map(q => q.id === updatedSet.id ? updatedSet : q));
  };

  // 1. 模版分类视图
  const renderTemplateCategories = () => (
    <div className="flex-1 flex flex-col bg-slate-50 animate-fade-in h-full">
      <div className="px-6 pt-12 pb-4 bg-white border-b border-slate-100 flex items-center space-x-4">
        <button onClick={() => setView('main')} className="p-1 -ml-1 text-slate-400 active:scale-90"><ChevronLeft size={28} /></button>
        <h3 className="text-xl font-black text-slate-900">模版中心</h3>
      </div>
      <div className="flex-1 overflow-y-auto p-6 pb-32">
        <div className="grid grid-cols-2 gap-4">
          {templateCategories.map((cat) => {
            const occupant = getBindingInfo(cat.name);
            return (
              <button 
                key={cat.id} 
                onClick={() => handleSelectCategory(cat)}
                className="bg-white p-6 rounded-[32px] shadow-sm border border-white flex flex-col items-start active:scale-95 transition-all text-left group relative"
              >
                {occupant && (
                  <div className="absolute top-4 right-4 text-emerald-500">
                    <LinkIcon size={14} />
                  </div>
                )}
                <div className={`${cat.color} w-12 h-12 rounded-2xl flex items-center justify-center text-white mb-6 shadow-lg shadow-slate-100`}>{cat.icon}</div>
                <h4 className="font-black text-slate-900 text-sm mb-1">{cat.name}</h4>
                <p className="text-[10px] font-bold text-slate-300 uppercase tracking-widest">{cat.count} 份模版</p>
                {occupant && (
                  <div className="mt-3 text-[8px] font-black text-emerald-600 bg-emerald-50 px-2 py-0.5 rounded-md">
                    关联中
                  </div>
                )}
              </button>
            );
          })}
        </div>
      </div>
    </div>
  );

  // 2. 模版列表视图
  const renderTemplateList = () => (
    <div className="flex-1 flex flex-col bg-slate-50 animate-fade-in h-full">
      <div className="px-6 pt-12 pb-4 bg-white border-b border-slate-100 flex items-center space-x-4">
        <button onClick={() => setView('template-categories')} className="p-1 -ml-1 text-slate-400 active:scale-90"><ChevronLeft size={28} /></button>
        <h3 className="text-xl font-black text-slate-900">{selectedCat?.name}</h3>
      </div>
      <div className="flex-1 overflow-y-auto px-6 pt-6 pb-32 space-y-3">
        {selectedCat?.templates.map((t, i) => (
          <div key={i} className="w-full bg-white p-5 rounded-2xl border border-white shadow-sm flex items-center justify-between">
            <span className="text-[14px] font-bold text-slate-700">{t}</span>
            <ChevronRight size={16} className="text-slate-200" />
          </div>
        ))}
      </div>
    </div>
  );

  // 3. 问题清单列表视图
  const renderQuestionsView = () => (
    <div className="flex-1 flex flex-col bg-slate-50 animate-fade-in h-full relative">
      <div className="px-6 pt-12 pb-4 bg-white border-b border-slate-100 flex items-center justify-between">
        <div className="flex items-center space-x-4">
          <button onClick={() => setView('main')} className="p-1 -ml-1 text-slate-400 active:scale-90"><ChevronLeft size={28} /></button>
          <h3 className="text-xl font-black text-slate-900">问题清单</h3>
        </div>
        <button 
          onClick={() => setIsCreatingNew(true)}
          className="w-11 h-11 bg-emerald-500 text-white rounded-2xl flex items-center justify-center active:scale-90 shadow-lg shadow-emerald-100"
        >
          <PlusCircle size={24} />
        </button>
      </div>

      <div className="flex-1 overflow-y-auto px-6 pt-6 pb-32 space-y-4">
        {questionSets.map((set) => (
          <div 
            key={set.id} 
            className="w-full bg-white p-6 rounded-[36px] border border-white shadow-sm flex flex-col active:scale-[0.98] transition-all relative"
          >
            <button 
              onClick={(e) => { e.stopPropagation(); setEditingQuestionSet(set); }}
              className="absolute top-6 right-6 p-2 bg-slate-50 text-slate-400 rounded-xl active:bg-slate-100"
            >
              <Settings2 size={18} />
            </button>

            <div className="flex items-start justify-between mb-3 pr-10">
              <div className="flex items-center space-x-3">
                <div className="w-10 h-10 bg-emerald-50 text-emerald-600 rounded-xl flex items-center justify-center">
                  <CheckSquare size={20} />
                </div>
                <div>
                  <h4 className="font-black text-slate-800 text-[15px]">{set.title}</h4>
                  <p className="text-[10px] text-emerald-600 font-bold uppercase tracking-wider">{set.questions.length} QUESTIONS</p>
                </div>
              </div>
            </div>

            <p className="text-[11px] text-slate-400 font-medium mb-5 px-1 leading-relaxed line-clamp-2">{set.desc}</p>

            <div className="flex items-center space-x-3 pt-4 border-t border-slate-50">
              <button 
                onClick={() => { setActiveEditorSet(set); setView('question-editor'); }}
                className="flex-1 py-3 bg-emerald-500 text-white rounded-xl text-[11px] font-black uppercase tracking-widest flex items-center justify-center space-x-2 shadow-lg shadow-emerald-100"
              >
                <span>配置问题内容</span>
                <ArrowRight size={14} />
              </button>
              <div className="px-3 py-3 bg-slate-50 rounded-xl text-slate-400 flex items-center space-x-1.5">
                 <LinkIcon size={10} />
                 <span className="text-[9px] font-black">{set.linkedTemplate || '未绑定'}</span>
              </div>
            </div>
          </div>
        ))}
      </div>

      {/* 属性设置 Overlay */}
      {(isCreatingNew || editingQuestionSet) && (
        <div className="absolute inset-0 z-[200] bg-black/60 backdrop-blur-md flex items-end justify-center">
          <div className="w-full max-w-md bg-white rounded-t-[48px] p-8 animate-slide-up shadow-2xl">
            <div className="flex items-center justify-between mb-8">
              <h3 className="text-2xl font-black text-slate-900">{isCreatingNew ? '新建清单' : '清单设置'}</h3>
              <button onClick={() => { setIsCreatingNew(false); setEditingQuestionSet(null); }} className="p-2 bg-slate-100 rounded-full"><X size={20} /></button>
            </div>
            <div className="space-y-6">
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-300 uppercase tracking-widest px-1">清单名称</label>
                <input 
                  type="text"
                  placeholder="例如：行业深耕挖掘清单"
                  value={isCreatingNew ? newSetData.title : editingQuestionSet?.title}
                  onChange={(e) => isCreatingNew 
                    ? setNewSetData({ ...newSetData, title: e.target.value })
                    : setEditingQuestionSet(prev => prev ? { ...prev, title: e.target.value } : null)
                  }
                  className="w-full h-14 bg-slate-50 rounded-2xl px-5 font-bold text-slate-700 outline-none focus:ring-2 focus:ring-blue-100"
                />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-300 uppercase tracking-widest px-1">关联行业模版 (单选)</label>
                <div className="relative">
                  <button 
                    onClick={() => setShowBindingSelector(true)}
                    className="w-full h-16 bg-blue-50/50 border-2 border-dashed border-blue-200 rounded-2xl flex items-center justify-between px-6 group active:bg-blue-100/50 transition-all"
                  >
                    <div className="flex items-center space-x-3">
                      <LinkIcon size={16} className="text-blue-500" />
                      <span className="font-black text-blue-700 text-sm">
                        {(isCreatingNew ? newSetData.linkedTemplate : editingQuestionSet?.linkedTemplate) || "点击绑定行业模版"}
                      </span>
                    </div>
                    <ChevronRight size={18} className="text-blue-300 group-active:translate-x-1 transition-transform" />
                  </button>
                  {((!isCreatingNew && editingQuestionSet?.linkedTemplate) || (isCreatingNew && newSetData.linkedTemplate)) && (
                    <button 
                      onClick={(e) => { e.stopPropagation(); isCreatingNew ? setNewSetData({...newSetData, linkedTemplate: undefined}) : handleUnbindTemplate(); }}
                      className="absolute -right-2 -top-2 w-6 h-6 bg-red-500 text-white rounded-full flex items-center justify-center shadow-lg"
                    >
                      <X size={12} />
                    </button>
                  )}
                </div>
              </div>
              <div className="space-y-2 pb-4">
                <label className="text-[10px] font-black text-slate-300 uppercase tracking-widest px-1">简要描述</label>
                <textarea 
                  placeholder="描述此清单的使用场景..."
                  rows={2}
                  value={isCreatingNew ? newSetData.desc : editingQuestionSet?.desc}
                  onChange={(e) => isCreatingNew 
                    ? setNewSetData({ ...newSetData, desc: e.target.value })
                    : setEditingQuestionSet(prev => prev ? { ...prev, desc: e.target.value } : null)
                  }
                  className="w-full bg-slate-50 rounded-2xl p-5 font-medium text-slate-600 outline-none focus:ring-2 focus:ring-blue-100 resize-none"
                />
              </div>
              <button 
                onClick={isCreatingNew ? handleCreateNew : handleSaveSettings}
                className="w-full py-5 bg-slate-900 text-white rounded-[24px] font-black text-sm shadow-2xl active:scale-95 transition-all"
              >
                {isCreatingNew ? '完成创建并编辑问题' : '保存设置修改'}
              </button>
            </div>
          </div>
        </div>
      )}

      {/* 行业模版绑定选择器 */}
      {showBindingSelector && (
        <div className="absolute inset-0 z-[300] bg-white flex flex-col animate-fade-in">
          <div className="px-6 pt-12 pb-6 flex items-center justify-between border-b border-slate-50">
            <div className="flex items-center space-x-4">
              <button onClick={() => setShowBindingSelector(false)} className="p-1"><ChevronLeft size={28} /></button>
              <h3 className="text-lg font-black text-slate-900">选择绑定模版</h3>
            </div>
            <div className="px-3 py-1 bg-amber-50 text-amber-600 rounded-lg flex items-center space-x-1.5">
               <AlertCircle size={10} />
               <span className="text-[8px] font-black uppercase">1:1 独占关系</span>
            </div>
          </div>
          <div className="flex-1 overflow-y-auto p-6 space-y-4">
            <p className="text-[10px] font-black text-slate-300 uppercase tracking-widest mb-2 px-1">每个行业分类仅能关联一个清单</p>
            {templateCategories.map((cat) => {
              const occupant = getBindingInfo(cat.name);
              const isOccupiedByOther = occupant && occupant.id !== (isCreatingNew ? 'new' : editingQuestionSet?.id);

              return (
                <button 
                  key={cat.id} 
                  onClick={() => handleBindTemplate(cat.name)}
                  className={`w-full p-6 rounded-[28px] border transition-all flex items-center justify-between group text-left ${
                    isOccupiedByOther 
                      ? 'bg-slate-50 border-slate-100 opacity-80' 
                      : 'bg-white border-slate-100 active:bg-blue-50 active:border-blue-200'
                  }`}
                >
                  <div className="flex items-center space-x-4">
                    <div className={`${cat.color} w-10 h-10 rounded-xl flex items-center justify-center text-white ${isOccupiedByOther ? 'grayscale opacity-50' : ''}`}>
                      {cat.icon}
                    </div>
                    <div>
                      <span className={`font-black ${isOccupiedByOther ? 'text-slate-400' : 'text-slate-800'}`}>{cat.name}</span>
                      {isOccupiedByOther && (
                        <p className="text-[9px] font-bold text-red-400 flex items-center mt-0.5">
                          <Link2Off size={10} className="mr-1" />
                          已绑定到: {occupant.title}
                        </p>
                      )}
                    </div>
                  </div>
                  <div className="flex items-center space-x-3">
                    {isOccupiedByOther && (
                      <span className="text-[8px] font-black text-amber-600 bg-amber-50 px-2 py-1 rounded-md">覆盖绑定</span>
                    )}
                    <div className={`w-6 h-6 rounded-full border-2 flex items-center justify-center ${
                      (isCreatingNew ? newSetData.linkedTemplate === cat.name : editingQuestionSet?.linkedTemplate === cat.name)
                        ? 'bg-blue-600 border-blue-600'
                        : 'border-slate-200'
                    }`}>
                      {(isCreatingNew ? newSetData.linkedTemplate === cat.name : editingQuestionSet?.linkedTemplate === cat.name) && (
                        <div className="w-2 h-2 bg-white rounded-full"></div>
                      )}
                    </div>
                  </div>
                </button>
              );
            })}
          </div>
          <div className="p-6 bg-slate-50 border-t border-slate-100">
            <div className="flex items-start space-x-3">
              <AlertCircle size={16} className="text-slate-300 mt-0.5 shrink-0" />
              <p className="text-[10px] text-slate-400 font-medium leading-relaxed">提示：如果选择“已绑定”的分类，系统将自动解除该分类与旧清单的关联，并与当前清单建立新链接。</p>
            </div>
          </div>
        </div>
      )}
    </div>
  );

  // 4. 清单内容编辑器视图
  const renderQuestionEditor = () => (
    <div className="flex-1 flex flex-col bg-slate-50 animate-fade-in h-full">
      <div className="px-6 pt-12 pb-6 bg-white border-b border-slate-100">
        <div className="flex items-center justify-between mb-4">
          <button onClick={() => setView('questions')} className="p-1 -ml-1 text-slate-400 active:scale-90"><ChevronLeft size={28} /></button>
          <div className="flex items-center space-x-2">
            <button 
              onClick={() => setEditingQuestionSet(activeEditorSet)}
              className="p-2 bg-slate-50 text-slate-400 rounded-xl active:bg-slate-100"
            >
              <Settings2 size={18} />
            </button>
            <button onClick={() => setView('questions')} className="px-4 py-2 bg-emerald-50 text-emerald-600 rounded-xl text-xs font-black">完成</button>
          </div>
        </div>
        <h3 className="text-xl font-black text-slate-900 leading-tight">{activeEditorSet?.title}</h3>
        <div className="flex items-center mt-2 space-x-2">
          <div className="px-2 py-0.5 bg-blue-50 text-blue-600 rounded-md flex items-center space-x-1">
            <LinkIcon size={10} />
            <span className="text-[9px] font-black uppercase">{activeEditorSet?.linkedTemplate || '未绑定模版'}</span>
          </div>
          <span className="text-[10px] text-slate-300 font-bold uppercase tracking-wider">{activeEditorSet?.questions.length} QUESTIONS</span>
        </div>
      </div>

      <div className="p-6 bg-white border-b border-slate-100">
        <div className="flex items-center space-x-3">
          <div className="flex-1 h-14 bg-slate-50 rounded-2xl px-5 flex items-center">
            <input 
              type="text"
              placeholder="添加一个新的访谈问题..."
              value={newQuestionInput}
              onChange={(e) => setNewQuestionInput(e.target.value)}
              onKeyDown={(e) => e.key === 'Enter' && handleAddQuestion()}
              className="w-full bg-transparent font-bold text-slate-700 outline-none text-sm"
            />
          </div>
          <button 
            onClick={handleAddQuestion}
            className="w-14 h-14 bg-emerald-500 text-white rounded-2xl flex items-center justify-center shadow-lg shadow-emerald-100 active:scale-90"
          >
            <Plus size={24} strokeWidth={3} />
          </button>
        </div>
      </div>

      <div className="flex-1 overflow-y-auto px-6 py-6 space-y-3 pb-32">
        {activeEditorSet?.questions.length === 0 ? (
          <div className="py-20 text-center opacity-30">
            <CheckSquare size={48} className="mx-auto text-slate-300 mb-4" />
            <p className="text-xs font-black uppercase tracking-widest text-slate-400">目前没有任何问题</p>
          </div>
        ) : (
          activeEditorSet?.questions.map((q, i) => (
            <div key={i} className="bg-white p-5 rounded-2xl border border-slate-100 flex items-start justify-between shadow-sm animate-fade-in">
              <div className="flex space-x-3">
                <span className="text-[10px] font-black text-emerald-500 mt-1">#{i + 1}</span>
                <p className="text-sm font-bold text-slate-700 leading-relaxed">{q}</p>
              </div>
              <button onClick={() => handleDeleteQuestion(i)} className="text-slate-300 hover:text-red-500 p-1">
                <Trash2 size={16} />
              </button>
            </div>
          ))
        )}
      </div>
    </div>
