export default InterviewDetail;

import React, { useState } from 'react';
import { 
  Layers, 
  ChevronRight, 
  ChevronLeft, 
  FileText, 
  CheckSquare, 
  Link as LinkIcon,
  X,
  PlusCircle,
  Grid,
  Trash2,
  Plus,
  ArrowRight,
  Settings2,
  AlertCircle,
  Link2Off
} from 'lucide-react';

type SubView = 'main' | 'template-categories' | 'template-list' | 'questions' | 'question-editor';

interface TemplateCategory {
  id: string;
  name: string;
  icon: React.ReactNode;
  color: string;
  count: number;
  templates: string[];
}

interface QuestionSet {
  id: string;
  title: string;
  desc: string;
  questions: string[];
  linkedTemplate?: string;
}

const Management: React.FC = () => {
  const [view, setView] = useState<SubView>('main');
  const [selectedCat, setSelectedCat] = useState<TemplateCategory | null>(null);
  const [editingQuestionSet, setEditingQuestionSet] = useState<QuestionSet | null>(null);
  const [activeEditorSet, setActiveEditorSet] = useState<QuestionSet | null>(null);
  const [isCreatingNew, setIsCreatingNew] = useState(false);
  const [showBindingSelector, setShowBindingSelector] = useState(false);
  const [newQuestionInput, setNewQuestionInput] = useState('');

  // 行业模版分类数据
  const templateCategories: TemplateCategory[] = [
    { id: 't1', name: '互联网/SaaS', icon: <Layers size={18} />, color: 'bg-blue-500', count: 12, templates: ['B端通用调研模版', '核心系统迁移评估', '数字化转型深度访谈'] },
    { id: 't2', name: '传统制造业', icon: <Layers size={18} />, color: 'bg-orange-500', count: 8, templates: ['供应链优化访谈', '数字化工厂建设', '能耗管理审计'] },
    { id: 't3', name: '金融/保险', icon: <Layers size={18} />, color: 'bg-emerald-500', count: 5, templates: ['高净值客户资产配置', '普惠金融信贷评审'] },
    { id: 't4', name: '医疗健康', icon: <Layers size={18} />, color: 'bg-rose-500', count: 6, templates: ['智慧医疗系统需求', '医药合规访谈'] }
  ];

  // 问题清单数据
  const [questionSets, setQuestionSets] = useState<QuestionSet[]>([
    { id: 'q1', title: '核心痛点挖掘', desc: '用于初次拜访，深挖业务瓶颈', questions: ['目前最影响效率的环节是？', '是否有替换现有系统的计划？', '预算决策链包含哪些人？'], linkedTemplate: '互联网/SaaS' },
    { id: 'q2', title: '商务异议处理', desc: '针对价格、竞争对手的防御话术', questions: ['如何看待友商的报价？', '对我们服务时效的要求？'], linkedTemplate: '传统制造业' },
    { id: 'q3', title: '决策链调研', desc: '摸清内部审批流程与关键决策人', questions: [] },
  ]);

  // 新建状态管理
  const [newSetData, setNewSetData] = useState<Partial<QuestionSet>>({
    title: '',
    desc: '',
    linkedTemplate: undefined,
    questions: []
  });

  const handleSelectCategory = (cat: TemplateCategory) => {
    setSelectedCat(cat);
    setView('template-list');
  };

  const getBindingInfo = (templateName: string) => {
    return questionSets.find(q => q.linkedTemplate === templateName);
  };

  const handleBindTemplate = (templateName: string) => {
    const occupant = getBindingInfo(templateName);
    const currentId = isCreatingNew ? 'new' : editingQuestionSet?.id;
    if (occupant && occupant.id === currentId) {
      setShowBindingSelector(false);
      return;
    }
    if (isCreatingNew) {
      setNewSetData(prev => ({ ...prev, linkedTemplate: templateName }));
    } else if (editingQuestionSet) {
      const updated = { ...editingQuestionSet, linkedTemplate: templateName };
      setEditingQuestionSet(updated);
      if (activeEditorSet?.id === updated.id) setActiveEditorSet(updated);
    }
    if (occupant) {
      setQuestionSets(prev => prev.map(q => q.id === occupant.id ? { ...q, linkedTemplate: undefined } : q));
    }
    setShowBindingSelector(false);
  };

  const handleUnbindTemplate = () => {
    if (editingQuestionSet) {
      const updated = { ...editingQuestionSet, linkedTemplate: undefined };
      setEditingQuestionSet(updated);
      if (activeEditorSet?.id === updated.id) setActiveEditorSet(updated);
    }
  };

  const handleCreateNew = () => {
    if (!newSetData.title) return;
    const newId = `q${Date.now()}`;
    const newEntry: QuestionSet = {
      id: newId,
      title: newSetData.title || '未命名清单',
      desc: newSetData.desc || '暂无描述',
      questions: [],
      linkedTemplate: newSetData.linkedTemplate
    };
    setQuestionSets([newEntry, ...questionSets]);
    setIsCreatingNew(false);
    setNewSetData({ title: '', desc: '', linkedTemplate: undefined, questions: [] });
    setActiveEditorSet(newEntry);
    setView('question-editor');
  };

  const handleSaveSettings = () => {
    if (editingQuestionSet) {
      setQuestionSets(prev => prev.map(q => q.id === editingQuestionSet.id ? editingQuestionSet : q));
      if (activeEditorSet?.id === editingQuestionSet.id) setActiveEditorSet(editingQuestionSet);
      setEditingQuestionSet(null);
    }
  };

  const handleAddQuestion = () => {
    if (!newQuestionInput.trim() || !activeEditorSet) return;
    const updatedSet = { ...activeEditorSet, questions: [...activeEditorSet.questions, newQuestionInput.trim()] };
    setActiveEditorSet(updatedSet);
    setQuestionSets(prev => prev.map(q => q.id === updatedSet.id ? updatedSet : q));
    setNewQuestionInput('');
  };

  const handleDeleteQuestion = (index: number) => {
    if (!activeEditorSet) return;
    const updatedQuestions = [...activeEditorSet.questions];
    updatedQuestions.splice(index, 1);
    const updatedSet = { ...activeEditorSet, questions: updatedQuestions };
    setActiveEditorSet(updatedSet);
    setQuestionSets(prev => prev.map(q => q.id === updatedSet.id ? updatedSet : q));
  };

  // 1. 模版分类视图 (已优化紧凑度)
  const renderTemplateCategories = () => (
    <div className="flex-1 flex flex-col bg-slate-50 animate-fade-in h-full">
      <div className="px-6 pt-12 pb-4 bg-white border-b border-slate-100 flex items-center space-x-4">
        <button onClick={() => setView('main')} className="p-1 -ml-1 text-slate-400 active:scale-90"><ChevronLeft size={28} /></button>
        <h3 className="text-xl font-black text-slate-900">模版中心</h3>
      </div>
      <div className="flex-1 overflow-y-auto p-5 pb-32">
        <div className="grid grid-cols-2 gap-3">
          {templateCategories.map((cat) => {
            const occupant = getBindingInfo(cat.name);
            return (
              <button 
                key={cat.id} 
                onClick={() => handleSelectCategory(cat)}
                className="bg-white p-5 rounded-[24px] shadow-sm border border-slate-50 flex flex-col items-start active:scale-95 transition-all text-left group relative"
              >
                {occupant && <div className="absolute top-4 right-4 text-emerald-500"><LinkIcon size={12} /></div>}
                <div className={`${cat.color} w-10 h-10 rounded-xl flex items-center justify-center text-white mb-4 shadow-md shadow-slate-50`}>{cat.icon}</div>
                <h4 className="font-black text-slate-800 text-[13px] mb-1">{cat.name}</h4>
                <p className="text-[9px] font-bold text-slate-300 uppercase tracking-widest">{cat.count} 份模版</p>
              </button>
            );
          })}
        </div>
      </div>
    </div>
  );

  // 2. 模版列表视图
  const renderTemplateList = () => (
    <div className="flex-1 flex flex-col bg-slate-50 animate-fade-in h-full">
      <div className="px-6 pt-12 pb-4 bg-white border-b border-slate-100 flex items-center space-x-4">
        <button onClick={() => setView('template-categories')} className="p-1 -ml-1 text-slate-400 active:scale-90"><ChevronLeft size={28} /></button>
        <h3 className="text-xl font-black text-slate-900">{selectedCat?.name}</h3>
      </div>
      <div className="flex-1 overflow-y-auto px-6 pt-6 pb-32 space-y-2">
        {selectedCat?.templates.map((t, i) => (
          <div key={i} className="w-full bg-white p-4 rounded-xl border border-slate-50 shadow-sm flex items-center justify-between active:bg-slate-50">
            <span className="text-[13px] font-bold text-slate-700">{t}</span>
            <ChevronRight size={14} className="text-slate-200" />
          </div>
        ))}
      </div>
    </div>
  );

  // 3. 问题清单列表视图 (优化卡片尺寸)
  const renderQuestionsView = () => (
    <div className="flex-1 flex flex-col bg-slate-50 animate-fade-in h-full relative">
      <div className="px-6 pt-12 pb-4 bg-white border-b border-slate-100 flex items-center justify-between">
        <div className="flex items-center space-x-4">
          <button onClick={() => setView('main')} className="p-1 -ml-1 text-slate-400 active:scale-90"><ChevronLeft size={28} /></button>
          <h3 className="text-xl font-black text-slate-900">问题清单</h3>
        </div>
        <button 
          onClick={() => setIsCreatingNew(true)}
          className="w-10 h-10 bg-emerald-500 text-white rounded-xl flex items-center justify-center active:scale-90 shadow-md"
        >
          <PlusCircle size={22} />
        </button>
      </div>

      <div className="flex-1 overflow-y-auto px-5 pt-5 pb-32 space-y-3">
        {questionSets.map((set) => (
          <div 
            key={set.id} 
            className="w-full bg-white p-5 rounded-[24px] border border-slate-50 shadow-sm flex flex-col active:scale-[0.99] transition-all relative"
          >
            <button 
              onClick={(e) => { e.stopPropagation(); setEditingQuestionSet(set); }}
              className="absolute top-5 right-5 p-1.5 text-slate-300 hover:text-slate-500"
            >
              <Settings2 size={16} />
            </button>

            <div className="flex items-start justify-between mb-2 pr-8">
              <div className="flex items-center space-x-3">
                <div className="w-9 h-9 bg-emerald-50 text-emerald-600 rounded-lg flex items-center justify-center">
                  <CheckSquare size={18} />
                </div>
                <div>
                  <h4 className="font-black text-slate-800 text-[14px]">{set.title}</h4>
                  <p className="text-[9px] text-emerald-600 font-bold uppercase tracking-wider">{set.questions.length} 问题</p>
                </div>
              </div>
            </div>

            <p className="text-[11px] text-slate-400 font-medium mb-4 px-1 leading-relaxed line-clamp-1">{set.desc}</p>

            <div className="flex items-center space-x-2 pt-3 border-t border-slate-50">
              <button 
                onClick={() => { setActiveEditorSet(set); setView('question-editor'); }}
                className="flex-1 py-2.5 bg-emerald-500 text-white rounded-lg text-[10px] font-black uppercase tracking-widest flex items-center justify-center space-x-1.5"
              >
                <span>配置内容</span>
                <ArrowRight size={12} />
              </button>
              <div className="px-2.5 py-2.5 bg-slate-50 rounded-lg text-slate-400 flex items-center space-x-1">
                 <LinkIcon size={10} />
                 <span className="text-[8px] font-black">{set.linkedTemplate || '未绑定'}</span>
              </div>
            </div>
          </div>
        ))}
      </div>

      {/* 属性设置 Overlay (与之前保持一致) */}
      {(isCreatingNew || editingQuestionSet) && (
        <div className="absolute inset-0 z-[200] bg-black/40 backdrop-blur-sm flex items-end justify-center">
          <div className="w-full max-w-md bg-white rounded-t-[40px] p-7 animate-slide-up shadow-2xl">
            <div className="flex items-center justify-between mb-6">
              <h3 className="text-xl font-black text-slate-900">{isCreatingNew ? '新建清单' : '清单设置'}</h3>
              <button onClick={() => { setIsCreatingNew(false); setEditingQuestionSet(null); }} className="p-2 bg-slate-100 rounded-full"><X size={18} /></button>
            </div>
            <div className="space-y-5">
              <div className="space-y-2">
                <label className="text-[9px] font-black text-slate-300 uppercase tracking-widest px-1">清单名称</label>
                <input 
                  type="text"
                  placeholder="请输入清单名称"
                  value={isCreatingNew ? newSetData.title : editingQuestionSet?.title}
                  onChange={(e) => isCreatingNew 
                    ? setNewSetData({ ...newSetData, title: e.target.value })
                    : setEditingQuestionSet(prev => prev ? { ...prev, title: e.target.value } : null)
                  }
                  className="w-full h-12 bg-slate-50 rounded-xl px-4 font-bold text-slate-700 outline-none focus:ring-1 focus:ring-blue-100 text-sm"
                />
              </div>
              <div className="space-y-2">
                <label className="text-[9px] font-black text-slate-300 uppercase tracking-widest px-1">关联行业模版</label>
                <button 
                  onClick={() => setShowBindingSelector(true)}
                  className="w-full h-14 bg-blue-50/50 border-2 border-dashed border-blue-200 rounded-xl flex items-center justify-between px-5 group active:bg-blue-100/50 transition-all"
                >
                  <div className="flex items-center space-x-2">
                    <LinkIcon size={14} className="text-blue-500" />
                    <span className="font-black text-blue-700 text-xs truncate max-w-[180px]">
                      {(isCreatingNew ? newSetData.linkedTemplate : editingQuestionSet?.linkedTemplate) || "点击选择模版"}
                    </span>
                  </div>
                  <ChevronRight size={14} className="text-blue-300" />
                </button>
              </div>
              <div className="space-y-2">
                <label className="text-[9px] font-black text-slate-300 uppercase tracking-widest px-1">描述</label>
                <textarea 
                  placeholder="场景描述..."
                  rows={2}
                  value={isCreatingNew ? newSetData.desc : editingQuestionSet?.desc}
                  onChange={(e) => isCreatingNew 
                    ? setNewSetData({ ...newSetData, desc: e.target.value })
                    : setEditingQuestionSet(prev => prev ? { ...prev, desc: e.target.value } : null)
                  }
                  className="w-full bg-slate-50 rounded-xl p-4 font-medium text-slate-600 outline-none focus:ring-1 focus:ring-blue-100 resize-none text-sm"
                />
              </div>
              <button 
                onClick={isCreatingNew ? handleCreateNew : handleSaveSettings}
                className="w-full py-4 bg-slate-900 text-white rounded-xl font-black text-sm shadow-xl active:scale-95 transition-all mt-2"
              >
                {isCreatingNew ? '下一步' : '保存'}
              </button>
            </div>
          </div>
        </div>
      )}

      {/* 行业模版绑定选择器 */}
      {showBindingSelector && (
        <div className="absolute inset-0 z-[300] bg-white flex flex-col animate-fade-in">
          <div className="px-6 pt-12 pb-4 flex items-center justify-between border-b border-slate-50">
            <button onClick={() => setShowBindingSelector(false)} className="p-1"><ChevronLeft size={28} /></button>
            <h3 className="text-lg font-black text-slate-900">选择模版</h3>
            <div className="w-10"></div>
          </div>
          <div className="flex-1 overflow-y-auto p-5 space-y-3">
            {templateCategories.map((cat) => {
              const occupant = getBindingInfo(cat.name);
              const isOccupiedByOther = occupant && occupant.id !== (isCreatingNew ? 'new' : editingQuestionSet?.id);
              return (
                <button 
                  key={cat.id} 
                  onClick={() => handleBindTemplate(cat.name)}
                  className={`w-full p-5 rounded-2xl border flex items-center justify-between text-left ${
                    isOccupiedByOther ? 'bg-slate-50 opacity-60' : 'bg-white border-slate-100 active:bg-blue-50'
                  }`}
                >
                  <div className="flex items-center space-x-3">
                    <div className={`${cat.color} w-8 h-8 rounded-lg flex items-center justify-center text-white`}>{cat.icon}</div>
                    <div>
                      <span className="font-black text-slate-800 text-sm">{cat.name}</span>
                      {isOccupiedByOther && <p className="text-[8px] font-bold text-red-400">已被占用</p>}
                    </div>
                  </div>
                  <div className={`w-5 h-5 rounded-full border-2 flex items-center justify-center ${
                    (isCreatingNew ? newSetData.linkedTemplate === cat.name : editingQuestionSet?.linkedTemplate === cat.name)
                      ? 'bg-blue-600 border-blue-600' : 'border-slate-200'
                  }`}>
                    {(isCreatingNew ? newSetData.linkedTemplate === cat.name : editingQuestionSet?.linkedTemplate === cat.name) && <div className="w-1.5 h-1.5 bg-white rounded-full"></div>}
                  </div>
                </button>
              );
            })}
          </div>
        </div>
      )}
    </div>
  );

  // 4. 内容编辑器 (保持功能，微调间距)
  const renderQuestionEditor = () => (
    <div className="flex-1 flex flex-col bg-slate-50 animate-fade-in h-full">
      <div className="px-6 pt-12 pb-4 bg-white border-b border-slate-100 flex items-center justify-between">
        <button onClick={() => setView('questions')} className="p-1 -ml-1 text-slate-400 active:scale-90"><ChevronLeft size={28} /></button>
        <div className="text-center">
           <h3 className="text-sm font-black text-slate-900 truncate max-w-[200px]">{activeEditorSet?.title}</h3>
           <span className="text-[9px] font-black text-blue-500 uppercase tracking-widest">{activeEditorSet?.linkedTemplate || '未绑定'}</span>
        </div>
        <button onClick={() => setView('questions')} className="px-3 py-1.5 bg-emerald-50 text-emerald-600 rounded-lg text-[10px] font-black uppercase">保存</button>
      </div>

      <div className="p-4 bg-white border-b border-slate-50 flex items-center space-x-2">
        <input 
          type="text"
          placeholder="添加问题..."
          value={newQuestionInput}
          onChange={(e) => setNewQuestionInput(e.target.value)}
          onKeyDown={(e) => e.key === 'Enter' && handleAddQuestion()}
          className="flex-1 h-12 bg-slate-50 rounded-xl px-4 font-bold text-slate-700 outline-none text-sm"
        />
        <button 
          onClick={handleAddQuestion}
          className="w-12 h-12 bg-emerald-500 text-white rounded-xl flex items-center justify-center active:scale-90"
        >
          <Plus size={20} strokeWidth={3} />
        </button>
      </div>

      <div className="flex-1 overflow-y-auto px-5 py-5 space-y-2 pb-32">
        {activeEditorSet?.questions.length === 0 ? (
          <div className="py-16 text-center opacity-30">
            <CheckSquare size={40} className="mx-auto text-slate-300 mb-3" />
            <p className="text-[10px] font-black uppercase tracking-widest text-slate-400">清单为空</p>
          </div>
        ) : (
          activeEditorSet?.questions.map((q, i) => (
            <div key={i} className="bg-white p-4 rounded-xl border border-slate-50 flex items-start justify-between shadow-sm animate-fade-in">
              <div className="flex space-x-3">
                <span className="text-[10px] font-black text-emerald-500 mt-0.5">#{i + 1}</span>
                <p className="text-[13px] font-bold text-slate-700 leading-relaxed">{q}</p>
              </div>
              <button onClick={() => handleDeleteQuestion(i)} className="text-slate-200 hover:text-red-400 p-1 shrink-0 ml-2">
                <Trash2 size={14} />
              </button>
            </div>
          ))
        )}
      </div>
    </div>
  );

  // 主视图 (重大更新：采用紧凑的网格入口)
  if (view === 'template-categories') return renderTemplateCategories();
  if (view === 'template-list') return renderTemplateList();
  if (view === 'questions') return renderQuestionsView();
  if (view === 'question-editor') return renderQuestionEditor();

  return (
    <div className="h-full bg-slate-50 flex flex-col animate-fade-in">
      <div className="px-6 pt-12 pb-6">
        <h2 className="text-2xl font-black text-slate-900 tracking-tight">业务支撑管理</h2>
        <p className="text-[10px] font-bold text-slate-400 mt-1 uppercase tracking-widest tracking-[0.2em]">Workspace Support</p>
      </div>

      {/* 紧凑网格布局 */}
      <div className="px-6 grid grid-cols-2 gap-4">
        <button 
          onClick={() => setView('template-categories')}
          className="bg-white p-5 rounded-[28px] border border-white shadow-sm flex flex-col items-start active:scale-[0.96] transition-all group relative overflow-hidden h-[180px]"
        >
          <div className="absolute -right-4 -top-4 w-24 h-24 bg-blue-50 rounded-full"></div>
          <div className="w-11 h-11 bg-blue-600 text-white rounded-[16px] flex items-center justify-center mb-6 shadow-lg shadow-blue-100 relative z-10">
            <Grid size={22} strokeWidth={2.5} />
          </div>
          <h4 className="font-black text-slate-900 text-base mb-1 relative z-10">模版中心</h4>
          <p className="text-[9px] text-slate-400 font-bold uppercase tracking-widest leading-relaxed relative z-10">行业报告模版</p>
          <div className="mt-auto flex items-center text-blue-600 space-x-1 relative z-10">
            <span className="text-[10px] font-black uppercase tracking-wider">进入</span>
            <ChevronRight size={12} strokeWidth={3} />
          </div>
        </button>

        <button 
          onClick={() => setView('questions')}
          className="bg-slate-900 p-5 rounded-[28px] border border-slate-800 shadow-xl flex flex-col items-start active:scale-[0.96] transition-all group relative overflow-hidden h-[180px]"
        >
          <div className="absolute -right-4 -top-4 w-24 h-24 bg-white/5 rounded-full"></div>
          <div className="w-11 h-11 bg-emerald-500 text-white rounded-[16px] flex items-center justify-center mb-6 shadow-xl shadow-emerald-900/40 relative z-10">
            <Layers size={22} strokeWidth={2.5} />
          </div>
          <h4 className="font-black text-white text-base mb-1 relative z-10">问题清单</h4>
          <p className="text-[9px] text-slate-500 font-bold uppercase tracking-widest leading-relaxed relative z-10">话术清单绑定</p>
          <div className="mt-auto flex items-center text-emerald-400 space-x-1 relative z-10">
            <span className="text-[10px] font-black uppercase tracking-wider">配置</span>
            <ChevronRight size={12} strokeWidth={3} />
          </div>
        </button>
      </div>

      {/* 底部装饰或提示 */}
      <div className="mt-auto p-8 opacity-[0.05] flex justify-center">
        <Layers size={80} />
      </div>

      <style>{`
        @keyframes slide-up { from { transform: translateY(100%); } to { transform: translateY(0); } }
        .animate-slide-up { animation: slide-up 0.4s cubic-bezier(0.16, 1, 0.3, 1) forwards; }
      `}</style>
    </div>
  );
};

export default Management;
